# ── Hilfsfunktionen ──────────────────────────────────────────────────
def generiere_ticket_nr():
    return f"TKT-{datetime.datetime.now().strftime('%Y%m%d')}-{'.'.join(random.choices(string.ascii_uppercase+string.digits,k=4))}"

def lade_historie():
    if os.path.exists(HISTORIE_DATEI):
        try:
            with open(HISTORIE_DATEI,"r",encoding="utf-8") as f: return json.load(f)
        except: return []
    return []

def speichere_historie(tickets):
    with open(HISTORIE_DATEI,"w",encoding="utf-8") as f:
        json.dump(tickets,f,ensure_ascii=False,indent=2)

@st.cache_resource
def load_model(path):
    return YOLO(path)

def detect_best_module(image, lang):
    best_mod = None; best_conf = 0.0; best_img = None; best_anzahl = 0
    for mod_id, info in MODELLE[lang].items():
        try:
            model = load_model(info["model_path"])
            results = model(image)
            boxes = results[0].boxes
            if boxes is not None and len(boxes) > 0:
                conf = float(boxes.conf[0])
                if conf > best_conf:
                    best_conf = conf
                    best_mod = mod_id
                    best_img = Image.fromarray(results[0].plot())
                    best_anzahl = len(boxes)
        except: pass
    return best_mod, best_conf, best_img, best_anzahl

def erstelle_pdf(ticket, lang):
    buffer = io.BytesIO()
    doc = SimpleDocTemplate(buffer,pagesize=A4,rightMargin=2*cm,leftMargin=2*cm,topMargin=2*cm,bottomMargin=2*cm)
    st_t = ParagraphStyle("t",fontSize=16,fontName="Helvetica-Bold",spaceAfter=4,textColor=colors.HexColor("#1B2E6B"))
    st_s = ParagraphStyle("s",fontSize=9,fontName="Helvetica",spaceAfter=12,textColor=colors.HexColor("#888780"))
    st_sec = ParagraphStyle("sec",fontSize=11,fontName="Helvetica-Bold",spaceBefore=12,spaceAfter=4,textColor=colors.HexColor("#2C2C2A"))
    st_b = ParagraphStyle("b",fontSize=9,fontName="Helvetica",spaceAfter=3,textColor=colors.HexColor("#2C2C2A"))
    sf = {"Offen":colors.HexColor("#E24B4A"),"In Bearbeitung":colors.HexColor("#EF9F27"),"Abgeschlossen":colors.HexColor("#1D9E75"),
          "Open":colors.HexColor("#E24B4A"),"In Progress":colors.HexColor("#EF9F27"),"Closed":colors.HexColor("#1D9E75")}
    el=[]
    el.append(Paragraph("FMS50 – Maintenance System",st_t))
    el.append(Paragraph("FactoryLab FHWN",st_s))
    el.append(HRFlowable(width="100%",thickness=1,color=colors.HexColor("#D3D1C7")))
    el.append(Spacer(1,0.3*cm))
    if ticket.get("_img"):
        from reportlab.platypus import Image as RLI
        ib=io.BytesIO(); ticket["_img"].save(ib,format="JPEG"); ib.seek(0)
        el.append(RLI(ib,width=10*cm,height=7*cm,kind="proportional")); el.append(Spacer(1,0.2*cm))
    el.append(Paragraph("Ticket",st_sec))
    keys = ["Ticket-Nr.","Zeitstempel","Station","Modul","Komponente","SPS-Code","Fehlerbeschreibung",
            "Fehlerursache","Inspektion","Reparatur","Wiederverwendung","Ersatzteile","Bearbeiter/in",
            "Konfidenz-Erkennung","Status","Status seit"]
    daten=[[k, str(ticket.get(k,"–"))] for k in keys]
    tab=Table(daten,colWidths=[5*cm,11.7*cm])
    sv=sf.get(ticket.get("Status",""),colors.black)
    tab.setStyle(TableStyle([
        ("FONTNAME",(0,0),(0,-1),"Helvetica-Bold"),("FONTNAME",(1,0),(1,-1),"Helvetica"),
        ("FONTSIZE",(0,0),(-1,-1),9),("TEXTCOLOR",(0,0),(0,-1),colors.HexColor("#5F5E5A")),
        ("TEXTCOLOR",(1,0),(1,-1),colors.HexColor("#2C2C2A")),
        ("TEXTCOLOR",(1,14),(1,14),sv),("FONTNAME",(1,14),(1,14),"Helvetica-Bold"),
        ("ROWBACKGROUNDS",(0,0),(-1,-1),[colors.HexColor("#F1EFE8"),colors.white]),
        ("TOPPADDING",(0,0),(-1,-1),5),("BOTTOMPADDING",(0,0),(-1,-1),5),
        ("LEFTPADDING",(0,0),(-1,-1),6),("GRID",(0,0),(-1,-1),0.3,colors.HexColor("#D3D1C7")),
    ]))
    el.append(tab)
    doc.build(el); buffer.seek(0); return buffer

